#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

struct Edge {
    int v;
    long long cost;
    Edge(int _v, long long _cost) : v(_v), cost(_cost) {}
};

struct State {
    int u;
    long long total_cost;
    long long min_cost;
    State(int _u, long long _total, long long _min) : u(_u), total_cost(_total), min_cost(_min) {}
};

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        graph[u].emplace_back(v, cost);
    }

    long long max_score = -1;
    queue<State> q;
    q.emplace(0, 0, LLONG_MAX);

    while (!q.empty()) {
        State current = q.front();
        q.pop();
        int u = current.u;
        long long total = current.total_cost;
        long long min_cost = current.min_cost;

        if (u == n - 1) {
            if (total <= k) {
                if (min_cost != LLONG_MAX) {
                    max_score = max(max_score, min_cost);
                }
            }
            continue;
        }

        for (const Edge& edge : graph[u]) {
            int v = edge.v;
            long long cost = edge.cost;
            if (!online[v] && v != n - 1) {
                continue;
            }
            long long new_total = total + cost;
            if (new_total > k) {
                continue;
            }
            long long new_min = min(min_cost, cost);
            q.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}

